mapper.select:
SELECT id, product_id, stock, locked_stock, version
FROM t_inventory
WHERE product_id = #{productId}

mapper.update:
UPDATE t_inventory
SET stock = stock - #{quantity}, version = version + 1
WHERE product_id = #{productId}
  AND version = #{version}
  AND stock >= #{quantity}

UPDATE t_inventory
SET stock = stock + #{quantity}
WHERE product_id = #{productId}
